constexpr double kInf = std::numeric_limits<double>::infinity();

FitError make_fit_err(FitError::Kind kind, std::string detail) {
  return FitError{kind, std::move(detail), 0, 0.0};
}

FitError post_to_fit(const PostError& e, std::string_view where) {
  return make_fit_err(FitError::Kind::NumericIssue,
                      std::string(where) + ": " + e.detail);
}

double total_n(const data::SampleStats& samp) {
  double n = 0.0;
  for (const auto nb : samp.n_obs) n += static_cast<double>(nb);
  return n;
}

double total_n(const fiml::FIMLPack& pack) {
  return static_cast<double>(pack.cache.n_total);
}

