struct RBMParts {
  Eigen::MatrixXd information;
  Eigen::MatrixXd meat;
  double trace_term = 0.0;
  double penalty = 0.0;
  double penalty_per_observation = 0.0;
};

fit_expected<double>
trace_information_meat(const Eigen::MatrixXd& information,
                       const Eigen::MatrixXd& meat) {
  if (information.rows() != information.cols()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm: information matrix is not square"));
  }
  if (meat.rows() != information.rows() || meat.cols() != information.cols()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm: score meat shape does not match information"));
  }
  Eigen::FullPivLU<Eigen::MatrixXd> lu(information);
  if (!lu.isInvertible()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm: information matrix is singular"));
  }
  const Eigen::MatrixXd solved = lu.solve(meat);
  const double tr = solved.trace();
  if (!std::isfinite(tr)) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm: trace(j^-1 e) is not finite"));
  }
  return tr;
}

fit_expected<RBMParts>
parts_from_info_scores(Eigen::MatrixXd information,
                       const Eigen::MatrixXd& scores,
                       double n_total) {
  if (!(n_total > 0.0)) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm: non-positive sample size"));
  }
  Eigen::MatrixXd meat = scores.transpose() * scores;
  auto trace_or = trace_information_meat(information, meat);
  if (!trace_or.has_value()) return std::unexpected(trace_or.error());
  RBMParts out;
  out.information = std::move(information);
  out.meat = std::move(meat);
  out.trace_term = *trace_or;
  out.penalty = -0.5 * out.trace_term;
  out.penalty_per_observation = -out.penalty / n_total;
  return out;
}

