double fd_step(double x, const RBMOptions& opts) {
  return opts.fd_abs_step + opts.fd_rel_step * std::max(1.0, std::abs(x));
}

using PenaltyFn = std::function<fit_expected<double>(const Eigen::VectorXd&)>;
using PartsFn = std::function<fit_expected<RBMParts>(const Eigen::VectorXd&)>;

fit_expected<Eigen::VectorXd>
penalty_gradient_fd(const Eigen::VectorXd& x, const PenaltyFn& penalty,
                    const RBMOptions& opts, const char* who) {
  if (!(opts.fd_abs_step > 0.0) || !(opts.fd_rel_step >= 0.0)) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        std::string(who) + ": finite-difference steps must be positive"));
  }
  Eigen::VectorXd grad(x.size());
  for (Eigen::Index k = 0; k < x.size(); ++k) {
    const double h = fd_step(x(k), opts);
    Eigen::VectorXd xp = x;
    Eigen::VectorXd xm = x;
    xp(k) += h;
    xm(k) -= h;
    auto fp = penalty(xp);
    if (!fp.has_value()) return std::unexpected(fp.error());
    auto fm = penalty(xm);
    if (!fm.has_value()) return std::unexpected(fm.error());
    grad(k) = (*fp - *fm) / (2.0 * h);
  }
  return grad;
}

fit_expected<Eigen::VectorXd>
solve_linear(const Eigen::MatrixXd& A, const Eigen::VectorXd& b,
             const char* what) {
  Eigen::FullPivLU<Eigen::MatrixXd> lu(A);
  if (!lu.isInvertible()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        std::string(what) + ": linear system is singular"));
  }
  Eigen::VectorXd x = lu.solve(b);
  if (!x.allFinite()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        std::string(what) + ": solution is non-finite"));
  }
  return x;
}

struct Admissibility {
  bool admissible = true;
  bool bounds_satisfied = true;
  bool sigma_pd = true;
  std::vector<std::string> warnings;
};

Admissibility assess_admissibility(const RBMContext& ctx,
                                   const Eigen::VectorXd& theta,
                                   const Bounds& bounds,
                                   const RBMOptions& opts) {
  Admissibility out;
  if (!bounds.empty()) {
    if (bounds.lower.size() != theta.size() || bounds.upper.size() != theta.size()) {
      out.bounds_satisfied = false;
      out.warnings.push_back("bounds have incompatible dimension");
    } else {
      for (Eigen::Index k = 0; k < theta.size(); ++k) {
        if (theta(k) < bounds.lower(k) - opts.admissibility_tol ||
            theta(k) > bounds.upper(k) + opts.admissibility_tol) {
          out.bounds_satisfied = false;
          out.warnings.push_back("corrected estimate violates box bounds");
          break;
        }
      }
    }
  }

  auto sm = ctx.ev->sigma(theta);
  if (!sm.has_value()) {
    out.sigma_pd = false;
    out.warnings.push_back("implied covariance evaluation failed: " +
                           sm.error().detail);
  } else {
    for (const auto& S : sm->sigma) {
      Eigen::LLT<Eigen::MatrixXd> llt(0.5 * (S + S.transpose()));
      if (llt.info() != Eigen::Success) {
        out.sigma_pd = false;
        out.warnings.push_back("implied covariance is not positive definite");
        break;
      }
    }
  }
  out.admissible = out.bounds_satisfied && out.sigma_pd;
  if (!opts.check_admissibility) out.admissible = true;
  return out;
}

void fill_common_result(RBMResult& result, const RBMContext& ctx,
                        const RBMParts& parts, const Eigen::VectorXd& theta,
                        const Eigen::VectorXd& start_theta,
                        const Bounds& bounds, const RBMOptions& opts) {
  std::vector<std::string> warnings = std::move(result.warnings);
  result.correction = theta - start_theta;
  result.information = parts.information;
  result.meat = parts.meat;
  result.trace_term = parts.trace_term;
  result.penalty = parts.penalty;
  result.penalty_per_observation = parts.penalty_per_observation;
  result.penalized_fmin = result.estimates.fmin + parts.penalty_per_observation;
  result.estimates.diagnostics = finalize_fit_diagnostics(
      theta, *ctx.ev, ctx.con, ctx.nl, bounds);

  Admissibility ad = assess_admissibility(ctx, theta, bounds, opts);
  result.admissible = ad.admissible;
  result.bounds_satisfied = ad.bounds_satisfied;
  result.sigma_pd = ad.sigma_pd;
  warnings.insert(warnings.end(), ad.warnings.begin(), ad.warnings.end());
  result.warnings = std::move(warnings);
}

fit_expected<RBMResult>
explicit_impl(const RBMContext& ctx, const Estimates& base,
              const Bounds& bounds, const RBMOptions& opts,
              const PartsFn& parts_at, const char* who) {
  if (base.theta.size() != static_cast<Eigen::Index>(ctx.pt.n_free())) {
    return std::unexpected(make_fit_err(FitError::Kind::InvalidStartValues,
        std::string(who) + ": base theta has wrong length"));
  }
  auto parts_or = parts_at(base.theta);
  if (!parts_or.has_value()) return std::unexpected(parts_or.error());
  const RBMParts& parts = *parts_or;

  const Eigen::MatrixXd& K = ctx.con.K();
  const Eigen::VectorXd alpha0 = ctx.con.contract(base.theta);
  PenaltyFn penalty_alpha = [&](const Eigen::VectorXd& alpha)
      -> fit_expected<double> {
    auto p = parts_at(ctx.con.expand(alpha));
    if (!p.has_value()) return std::unexpected(p.error());
    return p->penalty;
  };
  auto grad_alpha_or = penalty_gradient_fd(alpha0, penalty_alpha, opts, who);
  if (!grad_alpha_or.has_value()) return std::unexpected(grad_alpha_or.error());

  const Eigen::MatrixXd j_alpha = K.transpose() * parts.information * K;
  auto delta_alpha_or = solve_linear(j_alpha, *grad_alpha_or,
                                     "rbm explicit correction");
  if (!delta_alpha_or.has_value()) {
    return std::unexpected(delta_alpha_or.error());
  }
  const Eigen::VectorXd theta_rbm = base.theta + K * (*delta_alpha_or);

  RBMResult result;
  result.estimates = base;
  result.estimates.theta = theta_rbm;
  auto fmin_or = base_fmin_at(ctx.base_objective, theta_rbm, who);
  if (fmin_or.has_value()) {
    result.estimates.fmin = *fmin_or;
  } else {
    result.estimates.fmin = std::numeric_limits<double>::quiet_NaN();
    result.warnings.push_back(fmin_or.error().detail);
  }
  result.adjustment = K * (*grad_alpha_or);
  fill_common_result(result, ctx, parts, theta_rbm, base.theta, bounds, opts);
  return result;
}

fit_expected<double>
penalized_value(const optim::ScalarProblem& base_objective,
                const PartsFn& parts_at, double n_total,
                const Eigen::VectorXd& theta) {
  Eigen::VectorXd grad(theta.size());
  const double f = base_objective.f(theta, grad);
  if (!std::isfinite(f)) return kInf;
  auto parts = parts_at(theta);
  if (!parts.has_value()) return kInf;
  return f + parts->trace_term / (2.0 * n_total);
}

fit_expected<Eigen::VectorXd>
objective_gradient_fd(const Eigen::VectorXd& x,
                      const std::function<double(const Eigen::VectorXd&)>& f,
                      const RBMOptions& opts) {
  Eigen::VectorXd grad(x.size());
  for (Eigen::Index k = 0; k < x.size(); ++k) {
    const double h = fd_step(x(k), opts);
    Eigen::VectorXd xp = x;
    Eigen::VectorXd xm = x;
    xp(k) += h;
    xm(k) -= h;
    const double fp = f(xp);
    const double fm = f(xm);
    if (!std::isfinite(fp) || !std::isfinite(fm)) {
      return std::unexpected(make_fit_err(FitError::Kind::NonFiniteObjective,
          "rbm implicit: finite-difference objective is non-finite"));
    }
    grad(k) = (fp - fm) / (2.0 * h);
  }
  return grad;
}

fit_expected<RBMResult>
implicit_impl(const RBMContext& ctx, const Estimates& start,
              const Bounds& bounds, const RBMOptions& opts,
              const PartsFn& parts_at, const char* who) {
  if (start.theta.size() != static_cast<Eigen::Index>(ctx.pt.n_free())) {
    return std::unexpected(make_fit_err(FitError::Kind::InvalidStartValues,
        std::string(who) + ": start theta has wrong length"));
  }

  optim::ScalarProblem rbm_prob;
  rbm_prob.n_param = static_cast<Eigen::Index>(ctx.pt.n_free());
  rbm_prob.expand = [](const Eigen::VectorXd& x) { return x; };
  rbm_prob.f = [&ctx, &parts_at, &opts](const Eigen::VectorXd& theta,
                                        Eigen::VectorXd& grad) -> double {
    auto value = [&ctx, &parts_at](const Eigen::VectorXd& t) -> double {
      auto v = penalized_value(ctx.base_objective, parts_at, ctx.n_total, t);
      return v.has_value() ? *v : kInf;
    };
    const double f0 = value(theta);
    if (!std::isfinite(f0)) {
      grad.setZero();
      return kInf;
    }
    auto g = objective_gradient_fd(theta, value, opts);
    if (!g.has_value()) {
      grad.setZero();
      return kInf;
    }
    grad = *g;
    return f0;
  };

  const optim::ScalarProblem* run_prob = &rbm_prob;
  optim::ScalarProblem prob_a;
  Eigen::VectorXd x0 = start.theta;
  Bounds run_bounds = bounds;
  if (ctx.con.active()) {
    prob_a = optim::reparameterize(rbm_prob, ctx.con);
    run_prob = &prob_a;
    x0 = ctx.con.contract(start.theta);
    run_bounds = {};
    if (!bounds.empty() && !ctx.con.group.empty()) {
      run_bounds = optim::fold_alpha_bounds(ctx.con, bounds);
      x0 = x0.cwiseMax(run_bounds.lower).cwiseMin(run_bounds.upper);
    }
  }

  if (run_prob->n_param == 0) {
    const Eigen::VectorXd theta = ctx.con.expand(Eigen::VectorXd(0));
    auto parts = parts_at(theta);
    if (!parts.has_value()) return std::unexpected(parts.error());
    auto fmin = base_fmin_at(ctx.base_objective, theta, who);
    if (!fmin.has_value()) return std::unexpected(fmin.error());
    RBMResult result;
    result.estimates = start;
    result.estimates.theta = theta;
    result.estimates.fmin = *fmin;
    result.adjustment = Eigen::VectorXd::Zero(theta.size());
    fill_common_result(result, ctx, *parts, theta, start.theta, bounds, opts);
    return result;
  }

  auto out_or = run_scalar(*run_prob, x0, run_bounds, opts.backend, opts.optim,
                           who);
  if (!out_or.has_value()) return std::unexpected(out_or.error());
  const Eigen::VectorXd theta = run_prob->expand(out_or->x);
  auto parts = parts_at(theta);
  if (!parts.has_value()) return std::unexpected(parts.error());
  auto fmin = base_fmin_at(ctx.base_objective, theta, who);
  if (!fmin.has_value()) return std::unexpected(fmin.error());

  RBMResult result;
  result.estimates = start;
  result.estimates.theta = theta;
  result.estimates.fmin = *fmin;
  result.estimates.iterations = out_or->iterations;
  result.estimates.f_evals = out_or->f_evals;
  result.estimates.g_evals = out_or->g_evals;
  result.estimates.optimizer_status = out_or->status;
  result.estimates.grad_inf_norm = out_or->grad_inf_norm;
  result.estimates.audit = std::move(out_or->audit);
  result.adjustment = Eigen::VectorXd::Zero(theta.size());
  fill_common_result(result, ctx, *parts, theta, start.theta, bounds, opts);
  return result;
}

fit_expected<void>
validate_raw_matches_sample(const data::SampleStats& samp,
                            const data::RawData& raw) {
  if (!raw.mask.empty()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm_ml: raw data with missingness requires the FIML RBM path"));
  }
  if (samp.S.size() != raw.X.size() || samp.n_obs.size() != raw.X.size()) {
    return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
        "rbm_ml: sample statistics and raw data have different block counts"));
  }
  for (std::size_t b = 0; b < raw.X.size(); ++b) {
    if (raw.X[b].rows() != samp.n_obs[b] ||
        raw.X[b].cols() != samp.S[b].rows()) {
      return std::unexpected(make_fit_err(FitError::Kind::NumericIssue,
          "rbm_ml: sample statistics and raw data dimensions differ"));
    }
  }
  return {};
}

