fit_expected<RBMResult>
rbm_explicit_ml(spec::LatentStructure pt,
                const model::MatrixRep& rep,
                const data::SampleStats& samp,
                const data::RawData& raw,
                const Estimates& base,
                Bounds bounds,
                RBMOptions opts) {
  auto valid = validate_raw_matches_sample(samp, raw);
  if (!valid.has_value()) return std::unexpected(valid.error());
  auto ctx = ml_context(std::move(pt), rep, samp, base.theta);
  if (!ctx.has_value()) return std::unexpected(ctx.error());
  PartsFn parts_at = [&ctx, &samp, &raw](const Eigen::VectorXd& theta) {
    return ml_parts(*ctx, samp, raw, theta);
  };
  return explicit_impl(*ctx, base, bounds, opts, parts_at, "rbm_explicit_ml");
}

